pragma solidity ^0.8.22;

import { ReentrancyGuardUpgradeable } from "@openzeppelin/contracts-upgradeable/utils/ReentrancyGuardUpgradeable.sol";
import { TokenEmitterRewards } from "@collectivexyz/protocol-rewards/src/abstract/TokenEmitter/TokenEmitterRewards.sol";
import { Ownable2StepUpgradeable } from "@openzeppelin/contracts-upgradeable/access/Ownable2StepUpgradeable.sol";
import { PausableUpgradeable } from "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";

import { VRGDAC } from "./libs/VRGDAC.sol";
import { toDaysWadUnsafe } from "./libs/SignedWadMath.sol";
import { Strings } from "@openzeppelin/contracts/utils/Strings.sol";
import { NontransferableERC20Votes } from "./NontransferableERC20Votes.sol";
import { IERC20TokenEmitter } from "./interfaces/IERC20TokenEmitter.sol";

import { IRevolutionBuilder } from "./interfaces/IRevolutionBuilder.sol";

contract ERC20TokenEmitter is
    IERC20TokenEmitter,
    ReentrancyGuardUpgradeable,
    TokenEmitterRewards,
    Ownable2StepUpgradeable,
    PausableUpgradeable
{
    // treasury address to pay funds to
    address public treasury;

    // The token that is being minted.
    NontransferableERC20Votes public token;

    // The VRGDA contract
    VRGDAC public vrgdac;

    // solhint-disable-next-line not-rely-on-time
    uint256 public startTime;

    /**
     * @notice A running total of the amount of tokens emitted.
     */
    int256 public emittedTokenWad;

    // The split of the purchase that is reserved for the creator of the Verb in basis points
    uint256 public creatorRateBps;

    // The split of (purchase proceeds * creatorRate) that is sent to the creator as ether in basis points
    uint256 public entropyRateBps;

    // The account or contract to pay the creator reward to
    address public creatorsAddress;

    ///                                                          ///
    ///                         IMMUTABLES                       ///
    ///                                                          ///

    /// @notice The contract upgrade manager
    IRevolutionBuilder private immutable manager;

    ///                                                          ///
    ///                         CONSTRUCTOR                      ///
    ///                                                          ///

    /// @param _manager The contract upgrade manager address
    /// @param _protocolRewards The protocol rewards contract address
    /// @param _protocolFeeRecipient The protocol fee recipient address
    constructor(
        address _manager,
        address _protocolRewards,
        address _protocolFeeRecipient
    ) payable TokenEmitterRewards(_protocolRewards, _protocolFeeRecipient) initializer {
        manager = IRevolutionBuilder(_manager);
    }

    ///                                                          ///
    ///                         INITIALIZER                      ///
    ///                                                          ///

    /**
     * @notice Initialize the token emitter
     * @param _initialOwner The initial owner of the token emitter
     * @param _erc20Token The ERC-20 token contract address
     * @param _vrgdac The VRGDA contract address
     * @param _treasury The treasury address to pay funds to
     * @param _creatorsAddress The address to pay the creator reward to
     */
    function initialize(
        address _initialOwner,
        address _erc20Token,
        address _treasury,
        address _vrgdac,
        address _creatorsAddress
    ) external initializer {
        require(msg.sender == address(manager), "Only manager can initialize");

        __Pausable_init();
        __ReentrancyGuard_init();

        require(_treasury != address(0), "Invalid treasury address");

        // Set up ownable
        __Ownable_init(_initialOwner);

        treasury = _treasury;
        creatorsAddress = _creatorsAddress;
        vrgdac = VRGDAC(_vrgdac);
        token = NontransferableERC20Votes(_erc20Token);
        startTime = block.timestamp;
    }

    function _mint(address _to, uint256 _amount) private {
        token.mint(_to, _amount);
    }

    function totalSupply() public view returns (uint) {
        // returns total supply issued so far
        return token.totalSupply();
    }

    function decimals() public view returns (uint8) {
        // returns decimals
        return token.decimals();
    }

    function balanceOf(address _owner) public view returns (uint) {
        // returns balance of address
        return token.balanceOf(_owner);
    }

    /**
     * @notice Pause the contract.
     * @dev This function can only be called by the owner when the
     * contract is unpaused.
     */
    function pause() external override onlyOwner {
        _pause();
    }

    /**
     * @notice Unpause the token emitter.
     * @dev This function can only be called by the owner when the
     * contract is paused.
     */
    function unpause() external override onlyOwner {
        _unpause();
    }

    /**
     * @notice A payable function that allows a user to buy tokens for a list of addresses and a list of basis points to split the token purchase between.
     * @param addresses The addresses to send purchased tokens to.
     * @param basisPointSplits The basis points of the purchase to send to each address.
     * @param protocolRewardsRecipients The addresses to pay the builder, purchaseRefferal, and deployer rewards to
     * @return tokensSoldWad The amount of tokens sold in wad units.
     */
    function buyToken(
        address[] calldata addresses,
        uint[] calldata basisPointSplits,
        ProtocolRewardAddresses calldata protocolRewardsRecipients
    ) public payable nonReentrant whenNotPaused returns (uint256 tokensSoldWad) {
        //prevent treasury from paying itself
        require(msg.sender != treasury && msg.sender != creatorsAddress, "Funds recipient cannot buy tokens");

        require(msg.value > 0, "Must send ether");
        // ensure the same number of addresses and bps
        require(addresses.length == basisPointSplits.length, "Parallel arrays required");

        // Get value left after protocol rewards
        uint256 msgValueRemaining = _handleRewardsAndGetValueToSend(
            msg.value,
            protocolRewardsRecipients.builder,
            protocolRewardsRecipients.purchaseReferral,
            protocolRewardsRecipients.deployer
        );

        //Share of purchase amount to send to treasury
        uint256 toPayTreasury = (msgValueRemaining * (10_000 - creatorRateBps)) / 10_000;

        //Share of purchase amount to reserve for creators
        //Ether directly sent to creators
        uint256 creatorDirectPayment = ((msgValueRemaining - toPayTreasury) * entropyRateBps) / 10_000;
        //Tokens to emit to creators
        int totalTokensForCreators = ((msgValueRemaining - toPayTreasury) - creatorDirectPayment) > 0
            ? getTokenQuoteForEther((msgValueRemaining - toPayTreasury) - creatorDirectPayment)
            : int(0);

        // Tokens to emit to buyers
        int totalTokensForBuyers = toPayTreasury > 0 ? getTokenQuoteForEther(toPayTreasury) : int(0);

        //Transfer ETH to treasury and update emitted
        emittedTokenWad += totalTokensForBuyers;
        if (totalTokensForCreators > 0) emittedTokenWad += totalTokensForCreators;

        //Deposit funds to treasury
        (bool success, ) = treasury.call{ value: toPayTreasury }(new bytes(0));
        require(success, "Transfer failed.");

        //Transfer ETH to creators
        if (creatorDirectPayment > 0) {
            (success, ) = creatorsAddress.call{ value: creatorDirectPayment }(new bytes(0));
            require(success, "Transfer failed.");
        }

        //Mint tokens for creators
        if (totalTokensForCreators > 0 && creatorsAddress != address(0)) {
            _mint(creatorsAddress, uint256(totalTokensForCreators));
        }

        uint256 bpsSum = 0;

        //Mint tokens to buyers

        for (uint256 i = 0; i < addresses.length; i++) {
            if (totalTokensForBuyers > 0) {
                // transfer tokens to address
                _mint(addresses[i], uint256((totalTokensForBuyers * int(basisPointSplits[i])) / 10_000));
            }
            bpsSum += basisPointSplits[i];
        }

        require(bpsSum == 10_000, "bps must add up to 10_000");

        emit PurchaseFinalized(
            msg.sender,
            msg.value,
            toPayTreasury,
            msg.value - msgValueRemaining,
            uint256(totalTokensForBuyers),
            uint256(totalTokensForCreators),
            creatorDirectPayment
        );

        return uint256(totalTokensForBuyers);
    }

    /**
     * @notice Returns the amount of wei that would be spent to buy an amount of tokens. Does not take into account the protocol rewards.
     * @param amount the amount of tokens to buy.
     * @return spentY The cost in wei of the token purchase.
     */
    function buyTokenQuote(uint256 amount) public view returns (int spentY) {
        require(amount > 0, "Amount must be greater than 0");
        // Note: By using toDaysWadUnsafe(block.timestamp - startTime) we are establishing that 1 "unit of time" is 1 day.
        // solhint-disable-next-line not-rely-on-time
        return
            vrgdac.xToY({
                timeSinceStart: toDaysWadUnsafe(block.timestamp - startTime),
                sold: emittedTokenWad,
                amount: int(amount)
            });
    }

    /**
     * @notice Returns the amount of tokens that would be emitted for an amount of wei. Does not take into account the protocol rewards.
     * @param etherAmount the payment amount in wei.
     * @return gainedX The amount of tokens that would be emitted for the payment amount.
     */
    function getTokenQuoteForEther(uint256 etherAmount) public view returns (int gainedX) {
        require(etherAmount > 0, "Ether amount must be greater than 0");
        // Note: By using toDaysWadUnsafe(block.timestamp - startTime) we are establishing that 1 "unit of time" is 1 day.
        // solhint-disable-next-line not-rely-on-time
        return
            vrgdac.yToX({
                timeSinceStart: toDaysWadUnsafe(block.timestamp - startTime),
                sold: emittedTokenWad,
                amount: int(etherAmount)
            });
    }

    /**
     * @notice Returns the amount of tokens that would be emitted for the payment amount, taking into account the protocol rewards.
     * @param paymentAmount the payment amount in wei.
     * @return gainedX The amount of tokens that would be emitted for the payment amount.
     */
    function getTokenQuoteForPayment(uint256 paymentAmount) external view returns (int gainedX) {
        require(paymentAmount > 0, "Payment amount must be greater than 0");
        // Note: By using toDaysWadUnsafe(block.timestamp - startTime) we are establishing that 1 "unit of time" is 1 day.
        // solhint-disable-next-line not-rely-on-time
        return
            vrgdac.yToX({
                timeSinceStart: toDaysWadUnsafe(block.timestamp - startTime),
                sold: emittedTokenWad,
                amount: int(((paymentAmount - computeTotalReward(paymentAmount)) * (10_000 - creatorRateBps)) / 10_000)
            });
    }

    /**
     * @notice Set the split of (purchase * creatorRate) that is sent to the creator as ether in basis points.
     * @dev Only callable by the owner.
     * @param _entropyRateBps New entropy rate in basis points.
     */
    function setEntropyRateBps(uint256 _entropyRateBps) external onlyOwner {
        require(_entropyRateBps <= 10_000, "Entropy rate must be less than or equal to 10_000");

        emit EntropyRateBpsUpdated(entropyRateBps = _entropyRateBps);
    }

    /**
     * @notice Set the split of the payment that is reserved for creators in basis points.
     * @dev Only callable by the owner.
     * @param _creatorRateBps New creator rate in basis points.
     */
    function setCreatorRateBps(uint256 _creatorRateBps) external onlyOwner {
        require(_creatorRateBps <= 10_000, "Creator rate must be less than or equal to 10_000");

        emit CreatorRateBpsUpdated(creatorRateBps = _creatorRateBps);
    }

    /**
     * @notice Set the creators address to pay the creatorRate to. Can be a contract.
     * @dev Only callable by the owner.
     */
    function setCreatorsAddress(address _creatorsAddress) external override onlyOwner nonReentrant {
        require(_creatorsAddress != address(0), "Invalid address");

        emit CreatorsAddressUpdated(creatorsAddress = _creatorsAddress);
    }
}

Upon careful review of the provided `ERC20TokenEmitter` contract snippet, I will discuss one particular code segment that presents as a potential vulnerability. This is a reentrancy issue related to the `buyToken` function, although at first glance, the use of the `nonReentrant` modifier suggests that this potential vulnerability should be mitigated.

Given that the `buyToken` function is complex and involves external calls to send ether, it is crucial to ensure that reentrancy guard mechanisms are effective in all potential code paths. The `nonReentrant` modifier applied to the `buyToken` function should, in theory, prevent reentrancy by using the `ReentrancyGuardUpgradeable` contract from OpenZeppelin, which manages call status through a state variable.

```solidity
// Potential vulnerability related to reentrancy in the buyToken function
function buyToken( ... ) public payable nonReentrant whenNotPaused returns (uint256 tokensSoldWad) {
  //...
  (bool success, ) = treasury.call{ value: toPayTreasury }(new bytes(0));
  require(success, "Transfer failed.");
  //...
  if (creatorDirectPayment > 0) {
    (success, ) = creatorsAddress.call{ value: creatorDirectPayment }(new bytes(0));
    require(success, "Transfer failed.");
  }
  //...
}
```

Looking closely at the `buyToken` function, we can see there are two external calls that send ether using the low-level `call` function: one sends ether to `treasury` (line with `treasury.call`) and one potentially sends ether to `creatorsAddress` (line with `creatorsAddress.call`). Although these calls are protected by the `nonReentrant` modifier, we need to ensure that every external contract address interacting with this function is similarly non-reentrant or, at a minimum, does not have fallback functions that can lead to reentrancy.

Reentrancy is a vulnerability that arises when external contract calls are made to untrusted contracts, allowing the called contract to take control and re-enter the calling contract before the initial function execution is completed. This can lead to effects such as double withdrawal, double spending, or other unintended changes in the state.

Here's how this could be exploited:

1. An attacker deploys a contract with a fallback function designed to re-enter the `ERC20TokenEmitter` contract when it receives ether.
2. The attacker then calls the `buyToken` function, including the attacker's contract address in the `addresses` array.
3. When the `ERC20TokenEmitter` contract sends ether to the attacker's contract address, it triggers the attacker's fallback function.
4. The fallback function then calls `buyToken` again before the initial `buyToken` call has finished execution.
5. This unexpected reentrancy could lead to manipulation of the contract state and token minting process or other unforeseen effects.

The reason why standard `transfer` and `send` methods for transferring ether are often recommended over `call` is because the gas stipend for `transfer` and `send` (`2300` gas) does not allow for state changes that could re-enter the contract. However, `call` forwards all remaining gas by default and allows for potential reentrant calls. Here's a proof with the affected lines:

```markdown
| Description | Action | Severity | Actors | Scenario | Type | Line |
|-------------|--------|----------|--------|----------|------|------|
| Potential reentrancy on raw ether transfers | Switch ether transfers to use `.transfer()` or `.send()` with proper error handling or implement additional checks on the contracts receiving ether. | High 🔥 | Attackers | Attacker exploits the contract by making it call back into itself while processing a purchase, which can manipulate the contract state. | Vulnerability | 248, 263 |
```

To mitigate this, it's recommended that the `buyToken` function should not make raw calls to transfer ether. Instead, it could use the `transfer` function or `send` combined with proper error handling or even better, utilize the `SafeERC20` wrapper provided by OpenZeppelin for any ERC20 token transfers, which comes with built-in reentrancy protection and safer ERC20 interaction patterns. Additionally, the contract could establish a withdrawal pattern where users withdraw funds to their addresses, rather than having the contract send funds directly.

Upon a closer examination and taking into account the `nonReentrant` modifier applied to the `buyToken` function, the reentrancy attack scenario provided in the previous responses would not be a valid vulnerability. The `nonReentrant` modifier from OpenZeppelin's `ReentrancyGuard` contract is specifically designed to protect against such attacks by not allowing functions marked with `nonReentrant` to be re-entered while they are executing.

The following is a simplified outline of how the `nonReentrant` modifier works in Solidity:

```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.22;

import "@openzeppelin/contracts-upgradeable/security/ReentrancyGuardUpgradeable.sol";

contract Example is ReentrancyGuardUpgradeable {
    bool private _locked;

    modifier nonReentrant() {
        require(!_locked, "ReentrancyGuard: reentrant call");
        _locked = true;
        _;
        _locked = false;
    }

    // Rest of the contract code
}
```

As described, when a function with the `nonReentrant` modifier is called, the modifier checks if the `_locked` variable is `false` (indicating no current execution of another `nonReentrant` function), sets `_locked` to `true`, and then proceeds to execute the function body.

With this protection in place, if an attempted reentrant call occurs, the check at the start of the modifier will fail (since `_locked` would be `true` during the original function execution), which will revert the attempted reentrant transaction. Therefore, provided that the `ReentrancyGuardUpgradeable` is correctly implemented, the previously mentioned reentrancy vulnerability scenario should not be possible.

Given this, we can conclude that a reentrancy attack is not a valid concern in this case because the `buyToken` function is correctly guarded by the `nonReentrant` modifier. Hence, the contract does not have the reentrancy vulnerability as previously described, and our previous vulnerability markdown should be disregarded.

